async () => {
    const hasQuestionnaire = await isVisible(by.text('Questionario Inteligente'), 6000);
    if (!hasQuestionnaire) {
      await waitFor(element(by.text('Treinos'))).toBeVisible().withTimeout(10000);
      await expect(element(by.text('Treinos'))).toBeVisible();
      return;
    }
    await waitFor(element(by.id('btn-questionario-continuar'))).toBeVisible().withTimeout(10000);
    for (let attempt = 0; attempt < 6; attempt += 1) {
      const visible = await isVisible(by.id('btn-questionario-continuar'), 600);
      if (visible) {
        break;
      }
      await element(by.type('com.facebook.react.views.scroll.ReactScrollView')).atIndex(0).swipe('up', 'fast', 0.8);
    }
    await element(by.id('btn-questionario-continuar')).tap();
    const navigatedOnFirstTap = await isVisible(by.text('Treinos'), 5000);
    if (!navigatedOnFirstTap) {
      await element(by.id('btn-questionario-continuar')).tap();
    }
    await waitFor(element(by.text('Treinos'))).toBeVisible().withTimeout(20000);
    await expect(element(by.text('Treinos'))).toBeVisible();
  }

